clc;        % Clear command window
clear;      % Clear workspace variables
close all;  % Close all figures

%% Generate Data for Sine Wave
x = linspace(0, 2*pi, 500);   % Higher resolution
y = sin(x);

%% Create Figure
figure('Name', 'Signal and Image Visualization', 'NumberTitle', 'off'); %[output:80221cec]

% --- Subplot 1: Sine Wave ---
subplot(2, 2, 1); %[output:80221cec]
plot(x, y, 'b', 'LineWidth', 2); %[output:80221cec]
grid on; %[output:80221cec]
xlabel('X (radians)'); %[output:80221cec]
ylabel('sin(X)'); %[output:80221cec]
title('Sine Function'); %[output:80221cec]
legend('sin(x)'); %[output:80221cec]

% --- Subplot 2: Cosine Wave (Added for completeness) ---
subplot(2, 2, 2); %[output:80221cec]
plot(x, cos(x), 'r', 'LineWidth', 2); %[output:80221cec]
grid on; %[output:80221cec]
xlabel('X (radians)'); %[output:80221cec]
ylabel('cos(X)'); %[output:80221cec]
title('Cosine Function'); %[output:80221cec]
legend('cos(x)'); %[output:80221cec]

% --- Subplot 3: Combined Plot (Added) ---
subplot(2, 2, 3); %[output:80221cec]
plot(x, y, 'b', 'LineWidth', 2);  %[output:80221cec]
hold on; %[output:80221cec]
plot(x, cos(x), 'r--', 'LineWidth', 2); %[output:80221cec]
grid on; %[output:80221cec]
xlabel('X (radians)'); %[output:80221cec]
ylabel('Amplitude'); %[output:80221cec]
title('Sine & Cosine Functions'); %[output:80221cec]
legend('sin(x)', 'cos(x)'); %[output:80221cec]
hold off; %[output:80221cec]

% --- Subplot 4: Image Display ---
try %[output:group:819feedb]
    a = imread('peppers.png');  % Read image
    subplot(2, 2, 4); %[output:80221cec]
    imshow(a); %[output:80221cec]
    title('Sample Image (peppers.png)'); %[output:80221cec]
catch
    subplot(2, 2, 4);
    text(0.1, 0.5, 'Image not found!', 'FontSize', 12, 'Color', 'red');
    axis off;
end %[output:group:819feedb]


